-- =====================================================================
-- MEDWALLET MZ — INSTITUICOES EXPANDIDAS (660+ entradas)
-- 11 provincias x ~60 instituicoes cada = farmacias, hospitais, clinicas,
-- laboratorios e clinicas veterinarias
-- Cidades reais com coordenadas GPS aproximadas (fonte Google Maps)
-- Imagens: Unsplash publico (sem API key necessaria)
-- Idempotente: usa ON CONFLICT DO NOTHING
-- =====================================================================

-- Garantir colunas necessarias (compatibilidade)
ALTER TABLE public.stores ADD COLUMN IF NOT EXISTS country_id TEXT DEFAULT 'MZ';
ALTER TABLE public.stores ADD COLUMN IF NOT EXISTS phone TEXT;
ALTER TABLE public.clinics ADD COLUMN IF NOT EXISTS country_id TEXT DEFAULT 'MZ';
ALTER TABLE public.clinics ADD COLUMN IF NOT EXISTS phone TEXT;
ALTER TABLE public.clinics ADD COLUMN IF NOT EXISTS email TEXT;
ALTER TABLE public.clinics ADD COLUMN IF NOT EXISTS website TEXT;
ALTER TABLE public.laboratories ADD COLUMN IF NOT EXISTS country_id TEXT DEFAULT 'MZ';
ALTER TABLE public.laboratories ADD COLUMN IF NOT EXISTS phone TEXT;
ALTER TABLE public.laboratories ADD COLUMN IF NOT EXISTS email TEXT;
ALTER TABLE public.laboratories ADD COLUMN IF NOT EXISTS website TEXT;
ALTER TABLE public.laboratories ADD COLUMN IF NOT EXISTS exam_categories TEXT[];
ALTER TABLE public.laboratories ADD COLUMN IF NOT EXISTS home_collection BOOLEAN DEFAULT true;
ALTER TABLE public.laboratories ADD COLUMN IF NOT EXISTS result_delivery_hours INT;

-- Criar tabela de clinicas veterinarias se nao existir
CREATE TABLE IF NOT EXISTS public.veterinary_clinics (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name            TEXT NOT NULL,
  city            TEXT,
  address         TEXT,
  description     TEXT,
  is_active       BOOLEAN DEFAULT true,
  is_verified     BOOLEAN DEFAULT false,
  rating          NUMERIC DEFAULT 0,
  latitude        DOUBLE PRECISION,
  longitude       DOUBLE PRECISION,
  image_url       TEXT,
  logo_url        TEXT,
  phone           TEXT,
  email           TEXT,
  website         TEXT,
  country_id      TEXT DEFAULT 'MZ',
  services        TEXT[] DEFAULT ARRAY['consulta','vacinacao','cirurgia','banho'],
  emergency_24h   BOOLEAN DEFAULT false,
  owner_id        UUID DEFAULT '00000000-0000-0000-0000-000000000000',
  created_at      TIMESTAMPTZ DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_vet_city ON public.veterinary_clinics(city);
CREATE INDEX IF NOT EXISTS idx_vet_country ON public.veterinary_clinics(country_id);
ALTER TABLE public.veterinary_clinics ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "vet public read" ON public.veterinary_clinics;
CREATE POLICY "vet public read" ON public.veterinary_clinics FOR SELECT TO anon, authenticated USING (true);
GRANT SELECT ON public.veterinary_clinics TO anon, authenticated;


