-- =====================================================================
-- RELATORIO FINAL — INSTITUICOES EXPANDIDAS
-- =====================================================================
SELECT
  'EXPANDIDO COMPLETO' as status,
  232 as farmacias_total,
  116 as hospitais_total,
  116 as clinicas_total,
  116 as laboratorios_total,
  116 as veterinarias_total,
  696 as total_geral,
  (SELECT count(*) FROM public.stores WHERE country_id='MZ') as farmacias_db,
  (SELECT count(*) FROM public.clinics WHERE country_id='MZ') as hospitais_clinicas_db,
  (SELECT count(*) FROM public.laboratories WHERE country_id='MZ') as laboratorios_db,
  (SELECT count(*) FROM public.veterinary_clinics WHERE country_id='MZ') as veterinarias_db;

